import React from 'react';
import uuid from '../../../utils/uuid';
import Badge from '../../atoms/Badge';

export type BlogProps = {
  title: string;
  url: string;
  backgroundURL: string;
  tags: Array<string>;
  description: string;
  publishedAt: string;
};

const Blog: React.FC<BlogProps> = ({
  title,
  url,
  backgroundURL,
  tags,
  description,
  publishedAt
}) => {
  return (
    <a href={url} target="_blank" rel="noreferrer">
      <div className="rounded border shadow overflow-hidden shadow-2xl">
        <div
          className="w-full pb-half bg-cover bg-center"
          style={{ backgroundImage: `url(${backgroundURL})` }}
        ></div>
        <div className="p-4">
          <div className="mb-4">
            {tags.map((tag: string) => {
              return (
                <Badge
                  key={uuid()}
                  bgColor="bg-gray-900"
                  className="inline-block mr-1"
                >
                  {tag}
                </Badge>
              );
            })}
          </div>
          <h2 className="mb-4">
            <b>{title}</b>
          </h2>
          <p className="mb-4 text-justify">{description}</p>
          <p className="text-gray-500">{publishedAt}</p>
        </div>
      </div>
    </a>
  );
};

export default Blog;
