import React from 'react';
import uuid from '../../../utils/uuid';
import Container from '../../atoms/Container';
import Blog from '../../molecules/Blog';
import Header from '../../molecules/Header';

export type BlogType = {
  title: string;
  description: string;
  url: string;
  urlToImage: string;
  publishedAt: string;
  tags: Array<string>;
};

export type BlogsProps = {
  id: string;
  title: string;
  subtitle: string;
  backgroundImage?: string;
  blogs?: Array<BlogType>;
};

const Blogs: React.FC<BlogsProps> = ({
  id,
  title,
  subtitle,
  backgroundImage = '',
  blogs = []
}) => {
  return (
    <div id={id} className="pb-16">
      <Container>
        <Header subtitle={subtitle}>{title}</Header>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {blogs.map((blog: BlogType) => {
            const { title, description, url, publishedAt, tags, urlToImage } =
              blog;
            const backgroundURL: string =
              urlToImage === '' ? backgroundImage.toString() : urlToImage;
            tags.sort();
            return (
              <Blog
                key={uuid()}
                title={title}
                description={description}
                url={url}
                publishedAt={publishedAt}
                backgroundURL={backgroundURL}
                tags={tags}
              />
            );
          })}
        </div>
      </Container>
    </div>
  );
};

export default Blogs;
