import React from 'react';
import {
  FaAsterisk,
  FaComments,
  FaDev,
  FaList,
  FaTools,
  FaUserTie
} from 'react-icons/fa';
import { Section } from '../components/organisms/Menu';
import LandingTemplate from '../components/templates/Landing';
import { base } from '../configs';
import {
  about,
  cta,
  hero,
  newsletter,
  portfolio,
  stats,
  team,
  testimonials
} from '../data';
import useAxios from '../hooks/useAxios';

const sections: Array<Section> = [
  { id: 'about', icon: <FaUserTie /> },
  { id: 'stats', icon: <FaAsterisk /> },
  { id: 'portfolio', icon: <FaList /> },
  { id: 'techstack', icon: <FaTools /> },
  { id: 'testimonials', icon: <FaComments /> },
  { id: 'blogs', icon: <FaDev /> }
];

const Home: React.FC = () => {
  const url = `${base}/api/dev-to/articles?perPage=4&tag=machinelearning`;
  const { data: blogs = [] } = useAxios({ url });

  return (
    <LandingTemplate
      sections={sections}
      hero={hero}
      about={about}
      stats={stats}
      logos={portfolio}
      team={team}
      cta={cta}
      testimonials={testimonials}
      blogs={{
        id: 'blogs',
        title: 'Blogs',
        subtitle:
          'Keep updated with new technologies and stories from other developers.',
        backgroundImage: '/images/blog.jpg',
        blogs
      }}
      newsletter={newsletter}
    />
  );
};

export default Home;
