import axios, { AxiosError, AxiosRequestConfig, AxiosResponse } from 'axios';
import get from 'lodash/get';
import { useEffect, useState } from 'react';

const axiosAsync = (
  options: AxiosRequestConfig
): Promise<{ data?: any; error?: any }> => {
  return new Promise((resolve) => {
    axios(options)
      .then((response: AxiosResponse) => {
        const data = get(response, 'data', {});
        resolve({ data });
      })
      .catch((axiosError: AxiosError) => {
        const error = get(axiosError, 'response.data', {});
        resolve({ error });
      });
  });
};

const useAxios = (
  defaultConfigs: AxiosRequestConfig
): {
  data: any;
  error: any;
  loading: boolean;
  refetch: () => void;
  updateConfigs: (configs: AxiosRequestConfig) => void;
} => {
  const [configs, setConfigs] = useState(defaultConfigs);
  const [data, setData] = useState(undefined);
  const [error, setError] = useState(undefined);
  const [loading, setLoading] = useState(false);
  const [refetchIndex, setRefetchIndex] = useState(0);

  const updateConfigs = (configs: AxiosRequestConfig) => setConfigs(configs);
  const refetch = () =>
    setRefetchIndex((prevRefetchIndex: number) => prevRefetchIndex + 1);

  useEffect(() => {
    const fetchData = async (): Promise<void> => {
      setLoading(true);
      const { data, error } = await axiosAsync(configs);
      setData(data);
      setError(error);
      setLoading(false);
    };
    fetchData();
  }, [refetchIndex, configs]);

  return { data, error, loading, refetch, updateConfigs };
};

export default useAxios;
